import React, { useEffect, useState } from 'react';
import { dashboardApi } from '../services/api';
import { Spinner } from '../components/common';
import { useAuth } from '../context/AuthContext';

function BarChart({ data, labelKey, countKey, color }) {
  if (!data || data.length === 0) return <p style={{ color: 'var(--muted)', fontSize: '0.85rem' }}>No data yet.</p>;
  const max = Math.max(...data.map((d) => d[countKey]));
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
      {data.map((item, i) => (
        <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <div style={{ width: 120, fontSize: '0.78rem', color: 'var(--charcoal)', textAlign: 'right', flexShrink: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {item[labelKey]}
          </div>
          <div style={{ flex: 1, background: 'var(--parchment)', borderRadius: 4, height: 18, overflow: 'hidden' }}>
            <div
              style={{
                width: `${(item[countKey] / max) * 100}%`,
                background: color || 'var(--sienna)',
                height: '100%',
                borderRadius: 4,
                minWidth: 4,
              }}
            />
          </div>
          <div style={{ width: 28, fontSize: '0.78rem', color: 'var(--muted)', textAlign: 'right', flexShrink: 0 }}>
            {item[countKey]}
          </div>
        </div>
      ))}
    </div>
  );
}

export default function DashboardPage() {
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    dashboardApi.stats()
      .then((res) => setStats(res.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <Spinner />;

  return (
    <>
      <div className="page-header">
        <h2>Dashboard</h2>
        <p>Welcome back, {user?.full_name} — here's your library network overview.</p>
      </div>
      <div className="page-content">
        {stats && (
          <>
            <div className="stats-grid">
              {[
                { label: 'Libraries', value: stats.total_libraries },
                { label: 'Books', value: stats.total_books },
                { label: 'Requests', value: stats.total_requests },
                { label: 'Users', value: stats.total_users },
              ].map((s) => (
                <div key={s.label} className="stat-card">
                  <div className="stat-value">{s.value}</div>
                  <div className="stat-label">{s.label}</div>
                </div>
              ))}
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: 20 }}>
              <div className="card">
                <h4 style={{ marginBottom: 16, fontSize: '0.9rem', textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--muted)' }}>
                  Books by Status
                </h4>
                <BarChart data={stats.books_by_status} labelKey="status" countKey="count" color="var(--sienna)" />
              </div>

              <div className="card">
                <h4 style={{ marginBottom: 16, fontSize: '0.9rem', textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--muted)' }}>
                  Books by Genre
                </h4>
                <BarChart data={stats.books_by_genre} labelKey="genre" countKey="count" color="var(--forest)" />
              </div>

              <div className="card">
                <h4 style={{ marginBottom: 16, fontSize: '0.9rem', textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--muted)' }}>
                  Books by Language
                </h4>
                <BarChart data={stats.books_by_language} labelKey="language" countKey="count" color="var(--sage)" />
              </div>

              <div className="card">
                <h4 style={{ marginBottom: 16, fontSize: '0.9rem', textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--muted)' }}>
                  Top Authors
                </h4>
                <BarChart data={stats.books_by_author} labelKey="author" countKey="count" color="var(--charcoal)" />
              </div>
            </div>
          </>
        )}
      </div>
    </>
  );
}
